{
  "query": "mutation CreateClinicalOrder($orderData: ClinicalOrderInput!) { createOrder(orderData: $orderData) { id resourceType status intent category { coding { system code display } text } priority code { coding { system code display } text } subject { reference display } encounter { reference } occurrenceDatetime authoredOn requester { reference display } performer { reference display } reasonCode { coding { system code display } text } note { text authorString time } patientInstruction supportingInfo { reference display } specimen { reference display } bodySite { coding { system code display } text } } }",
  "variables": {
    "orderData": {
      "status": "DRAFT",
      "intent": "ORDER",
      "priority": "ROUTINE",
      "code": {
        "text": "Comprehensive Metabolic Panel",
        "coding": [{
          "system": "http://loinc.org",
          "code": "24323-8",
          "display": "Comprehensive metabolic 2000 panel - Serum or Plasma"
        }]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}",
        "display": "Test Patient"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}",
        "display": "Dr. Smith"
      },
      "category": [{
        "coding": [{
          "system": "http://terminology.hl7.org/CodeSystem/observation-category",
          "code": "laboratory",
          "display": "Laboratory"
        }],
        "text": "Laboratory Order"
      }],
      "reasonCode": [{
        "coding": [{
          "system": "http://snomed.info/sct",
          "code": "410620009",
          "display": "Well child visit"
        }],
        "text": "Annual physical examination"
      }],
      "note": [{
        "text": "Fasting required - patient instructed. Draw between 7-9 AM.",
        "authorString": "Dr. Smith",
        "time": "2024-01-15T10:30:00Z"
      }],
      "patientInstruction": "Please fast for 12 hours before blood draw. No food or drink except water after 8 PM the night before.",
      "supportingInfo": [{
        "reference": "Observation/previous-lab-123",
        "display": "Previous lab results"
      }],
      "specimen": [{
        "reference": "Specimen/serum-sample-456",
        "display": "Serum sample"
      }],
      "bodySite": [{
        "coding": [{
          "system": "http://snomed.info/sct",
          "code": "368209003",
          "display": "Right arm"
        }],
        "text": "Right antecubital fossa"
      }]
    }
  }
}

{
  "query": "mutation CreateMedicationOrder($orderData: MedicationOrderInput!) { createMedicationOrder(orderData: $orderData) { id resourceType status intent priority medicationCodeableConcept { coding { system code display } text } subject { reference display } encounter { reference } requester { reference display } dosageInstruction { text timing { repeat { frequency period periodUnit } } route { coding { system code display } } doseAndRate { doseQuantity { value unit system code } } } dispenseRequest { quantity { value unit } expectedSupplyDuration { value unit } numberOfRepeatsAllowed performer { reference display } } substitution { allowedBoolean reason { coding { system code display } } } reasonCode { coding { system code display } text } note { text authorString time } } }",
  "variables": {
    "orderData": {
      "status": "draft",
      "intent": "order",
      "priority": "routine",
      "medicationCodeableConcept": {
        "text": "Lisinopril 10mg Tablet",
        "coding": [{
          "system": "http://www.nlm.nih.gov/research/umls/rxnorm",
          "code": "314076",
          "display": "Lisinopril 10 MG Oral Tablet"
        }]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}",
        "display": "Test Patient"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}",
        "display": "Dr. Smith"
      },
      "dosageInstruction": [{
        "text": "Take 1 tablet by mouth daily in the morning with food",
        "timing": {
          "repeat": {
            "frequency": 1,
            "period": 1,
            "periodUnit": "d",
            "timeOfDay": ["08:00:00"],
            "when": ["CM"]
          }
        },
        "route": {
          "coding": [{
            "system": "http://snomed.info/sct",
            "code": "26643006",
            "display": "Oral route"
          }]
        },
        "doseAndRate": [{
          "doseQuantity": {
            "value": 10,
            "unit": "mg",
            "system": "http://unitsofmeasure.org",
            "code": "mg"
          }
        }],
        "maxDosePerPeriod": {
          "numerator": {
            "value": 10,
            "unit": "mg"
          },
          "denominator": {
            "value": 1,
            "unit": "d"
          }
        }
      }],
      "dispenseRequest": {
        "quantity": {
          "value": 30,
          "unit": "tablet"
        },
        "expectedSupplyDuration": {
          "value": 30,
          "unit": "days"
        },
        "numberOfRepeatsAllowed": 5,
        "performer": {
          "reference": "Organization/pharmacy-123",
          "display": "Main Street Pharmacy"
        }
      },
      "substitution": {
        "allowedBoolean": true,
        "reason": {
          "coding": [{
            "system": "http://terminology.hl7.org/CodeSystem/v3-ActReason",
            "code": "FP",
            "display": "formulary policy"
          }]
        }
      },
      "reasonCode": [{
        "coding": [{
          "system": "http://snomed.info/sct",
          "code": "38341003",
          "display": "Hypertensive disorder"
        }],
        "text": "Essential hypertension"
      }],
      "note": [{
        "text": "Monitor blood pressure weekly. Target BP <140/90. Check renal function in 2 weeks.",
        "authorString": "Dr. Smith",
        "time": "2024-01-15T10:30:00Z"
      }]
    }
  }
}

{
  "query": "mutation CreateLabOrder($orderData: LabOrderInput!) { createLabOrder(orderData: $orderData) { id resourceType status intent code { text } subject { reference } specimen { reference display } specimenRequirements { type { text } collection { method { text } bodySite { text } fastingStatus { text } } container { type { text } capacity { value unit } } } clinicalContext { indication { text } urgency priority } } }",
  "variables": {
    "orderData": {
      "status": "draft",
      "intent": "order",
      "code": {
        "text": "Lipid Panel with Reflex to LDL",
        "coding": [{
          "system": "http://loinc.org",
          "code": "57698-3",
          "display": "Lipid panel with direct LDL - Serum or Plasma"
        }]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}",
        "display": "Test Patient"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}",
        "display": "Dr. Smith"
      },
      "specimen": [{
        "reference": "Specimen/serum-lipid-789",
        "display": "Serum specimen for lipid analysis"
      }],
      "specimenRequirements": {
        "type": {
          "text": "Serum",
          "coding": [{
            "system": "http://snomed.info/sct",
            "code": "119364003",
            "display": "Serum specimen"
          }]
        },
        "collection": {
          "method": {
            "text": "Venipuncture",
            "coding": [{
              "system": "http://snomed.info/sct",
              "code": "28520004",
              "display": "Venipuncture"
            }]
          },
          "bodySite": {
            "text": "Antecubital fossa",
            "coding": [{
              "system": "http://snomed.info/sct",
              "code": "368209003",
              "display": "Right arm"
            }]
          },
          "fastingStatus": {
            "text": "12 hour fast required",
            "coding": [{
              "system": "http://terminology.hl7.org/CodeSystem/v2-0916",
              "code": "F",
              "display": "Patient was fasting prior to the procedure"
            }]
          }
        },
        "container": {
          "type": {
            "text": "Red top tube (no anticoagulant)",
            "coding": [{
              "system": "http://snomed.info/sct",
              "code": "702120003",
              "display": "Blood collection tube, no additive"
            }]
          },
          "capacity": {
            "value": 5,
            "unit": "mL"
          }
        }
      },
      "clinicalContext": {
        "indication": {
          "text": "Cardiovascular risk assessment - family history of CAD",
          "coding": [{
            "system": "http://snomed.info/sct",
            "code": "410620009",
            "display": "Well child visit"
          }]
        },
        "urgency": "routine",
        "priority": "normal"
      }
    }
  }
}

{
  "query": "mutation CreateImagingOrder($orderData: ImagingOrderInput!) { createImagingOrder(orderData: $orderData) { id resourceType status intent code { text } subject { reference } modality { text } bodySite { text } contrast { required type { text } contraindications { text } } radiationSafety { dose { value unit } pregnancy { status screening } } clinicalIndication { text } urgency priority } }",
  "variables": {
    "orderData": {
      "status": "draft",
      "intent": "order",
      "code": {
        "text": "CT Chest with IV Contrast",
        "coding": [{
          "system": "http://loinc.org",
          "code": "30746-2",
          "display": "CT Chest with IV contrast"
        }]
      },
      "subject": {
        "reference": "Patient/{{patient_id}}",
        "display": "Test Patient"
      },
      "encounter": {
        "reference": "Encounter/{{encounter_id}}"
      },
      "requester": {
        "reference": "Practitioner/{{practitioner_id}}",
        "display": "Dr. Smith"
      },
      "modality": {
        "text": "Computed Tomography",
        "coding": [{
          "system": "http://dicom.nema.org/resources/ontology/DCM",
          "code": "CT",
          "display": "Computed Tomography"
        }]
      },
      "bodySite": {
        "text": "Chest",
        "coding": [{
          "system": "http://snomed.info/sct",
          "code": "51185008",
          "display": "Thoracic structure"
        }]
      },
      "contrast": {
        "required": true,
        "type": {
          "text": "Iodinated contrast agent",
          "coding": [{
            "system": "http://snomed.info/sct",
            "code": "39290007",
            "display": "Iodinated contrast agent"
          }]
        },
        "contraindications": {
          "text": "Check renal function (eGFR >30), no known iodine allergy"
        }
      },
      "radiationSafety": {
        "dose": {
          "value": 7,
          "unit": "mSv",
          "system": "http://unitsofmeasure.org"
        },
        "pregnancy": {
          "status": "unknown",
          "screening": "Pregnancy screening required for women of childbearing age"
        }
      },
      "clinicalIndication": {
        "text": "Evaluate for pulmonary embolism - acute onset dyspnea and chest pain",
        "coding": [{
          "system": "http://snomed.info/sct",
          "code": "59282003",
          "display": "Pulmonary embolism"
        }]
      },
      "urgency": "urgent",
      "priority": "high"
    }
  }
}

{
  "query": "query GetOrder($id: ID!) { order(id: $id) { id status description patientId } }",
  "variables": {
    "id": "{{order_id}}"
  }
}

{
  "query": "mutation CreateOrderWithCDS($description: String!, $patientId: String!) { createOrder(description: $description, patientId: $patientId) { id status description patientId } }",
  "variables": {
    "description": "Warfarin 5mg daily - Check INR levels and drug interactions",
    "patientId": "{{patient_id}}"
  }
}

{
  "query": "query CheckDrugInteractions($patientId: String!, $medicationId: String!) { orders(patientId: $patientId) { id status description } }",
  "variables": {
    "patientId": "{{patient_id}}",
    "medicationId": "{{medication_id}}"
  }
}

{
  "query": "mutation CreateOrderSet($description: String!, $patientId: String!) { createOrder(description: $description, patientId: $patientId) { id status description patientId } }",
  "variables": {
    "description": "Hypertension Protocol: Lisinopril 10mg daily, Low sodium diet, BP monitoring q4h",
    "patientId": "{{patient_id}}"
  }
}

{
  "query": "mutation CreateDiabetesOrderSet($description: String!, $patientId: String!) { createOrder(description: $description, patientId: $patientId) { id status description patientId } }",
  "variables": {
    "description": "Diabetes Management: Metformin 500mg BID, HbA1c q3months, Diabetic diet consult",
    "patientId": "{{patient_id}}"
  }
}

{
  "query": "mutation SignOrder($orderId: ID!) { order(id: $orderId) { id status description } }",
  "variables": {
    "orderId": "{{order_id}}"
  }
}

{
  "query": "mutation HoldOrder($orderId: ID!) { order(id: $orderId) { id status description } }",
  "variables": {
    "orderId": "{{order_id}}"
  }
}

{
  "query": "mutation CancelOrder($orderId: ID!) { order(id: $orderId) { id status description } }",
  "variables": {
    "orderId": "{{order_id}}"
  }
}

{
  "query": "query PatientWithOrders($id: ID!) { patient(id: $id) { id name { given family } orders { id status description } } }",
  "variables": {
    "id": "{{patient_id}}"
  }
}

{
  "query": "query UserWithOrders($id: ID!) { user(id: $id) { id name email ordersRequested { id status description } } }",
  "variables": {
    "id": "{{practitioner_id}}"
  }
}

{
  "query": "query IntrospectionQuery { __schema { types { name kind description fields { name type { name kind ofType { name kind } } } } } }"
}
